  1→/**
  2→ * Intent Evidence Acceptance Test Kit
  3→ *
  4→ * Extends intent-test-kit with evidence-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   MCP tools: create_intent (with evidence_refs)
  9→ *   POST /api/intents/:id/evaluate  (SurrealQL EVENT target)
 10→ *   Workspace settings (direct DB for enforcement mode)
 11→ *   GET /api/workspaces/:ws/feed (governance feed)
 12→ */
 13→import { RecordId, type Surreal } from "surrealdb";
 14→import {
 15→  createDecisionDirectly,
 16→  createTaskDirectly,
 17→  createObservationDirectly,
 18→  createIntentDirectly,
 19→  createIdentity,
 20→  createLearningDirectly,
 21→  createGitCommitDirectly,
 22→  type CreateDecisionOpts,
 23→  type CreateTaskOpts,
 24→  type CreateObservationOpts,
 25→  type CreateLearningOpts,
 26→  type CreateGitCommitOpts,
 27→} from "../shared-fixtures";
 28→
 29→// Re-export everything from intent-test-kit
 30→export {
 31→  setupOrchestratorSuite,
 32→  createTestUser,
 33→  createTestWorkspace,
 34→  createReadyTask,
 35→  createTestProject,
 36→  getTestUserBearerToken,
 37→  fetchJson,
 38→  fetchRaw,
 39→  createDraftIntent,
 40→  submitIntent,
 41→  getIntentStatus,
 42→  getIntentRecord,
 43→  getIntentEvaluation,
 44→  waitForIntentStatus,
 45→  vetoIntent,
 46→  listPendingIntents,
 47→  createTestIdentity,
 48→  wireIntentEvaluationEvent,
 49→  simulateEvaluation,
 50→  createIntentViaMcp,
 51→  submitIntentViaMcp,
 52→  getIntentStatusViaMcp,
 53→  type IntentStatus,
 54→  type IntentRecord,
 55→  type EvaluationResult,
 56→  type CreateIntentOptions,
 57→  type BudgetLimit,
 58→  type ActionSpec,
 59→  type OrchestratorTestRuntime,
 60→  type TestUser,
 61→  type TestUserWithToken,
 62→  type TestWorkspace,
 63→  type TestTask,
 64→  type TestProject,
 65→} from "../intent-node/intent-test-kit";
 66→
 67→// Policy helpers for M3 tests
 68→export {
 69→  createPolicy,
 70→  activatePolicy,
 71→  type CreatePolicyOptions,
 72→} from "../policy-node/policy-test-kit";
 73→
 74→// ---------------------------------------------------------------------------
 75→// Evidence-Specific Types
 76→// ---------------------------------------------------------------------------
 77→
 78→export type EvidenceEnforcementMode = "bootstrap" | "soft" | "hard";
 79→
 80→export type EvidenceVerification = {
 81→  verified_count: number;
 82→  failed_refs?: string[];
 83→  verification_time_ms: number;
 84→  warnings?: string[];
 85→};
 86→
 87→export type EvidenceEnforcementThreshold = {
 88→  min_decisions: number;
 89→  min_tasks: number;
 90→};
 91→
 92→// ---------------------------------------------------------------------------
 93→// Evidence Entity Creation Helpers
 94→// ---------------------------------------------------------------------------
 95→
 96→/**
 97→ * Creates a confirmed decision to use as evidence.
 98→ * Returns the record ID for use in evidence_refs.
 99→ */
100→export async function createEvidenceDecision(
101→  surreal: Surreal,
102→  workspaceId: string,
103→  opts: {
104→    summary: string;
105→    status?: string;
106→    created_at?: Date;
107→  },
108→): Promise<{ decisionId: string; decisionRecord: RecordId<"decision"> }> {
109→  return createDecisionDirectly(surreal, workspaceId, {
110→    summary: opts.summary,
111→    status: opts.status ?? "confirmed",
112→    created_at: opts.created_at,
113→  });
114→}
115→
116→/**
117→ * Creates a completed task to use as evidence.
118→ * Returns the record ID for use in evidence_refs.
119→ */
120→export async function createEvidenceTask(
121→  surreal: Surreal,
122→  workspaceId: string,
123→  opts: {
124→    title: string;
125→    status?: string;
126→  },
127→): Promise<{ taskId: string; taskRecord: RecordId<"task"> }> {
128→  return createTaskDirectly(surreal, workspaceId, {
129→    title: opts.title,
130→    status: opts.status ?? "completed",
131→  });
132→}
133→
134→/**
135→ * Creates a verified observation to use as evidence.
136→ * Returns the record ID for use in evidence_refs.
137→ */
138→export async function createEvidenceObservation(
139→  surreal: Surreal,
140→  workspaceId: string,
141→  opts: {
142→    text: string;
143→    sourceAgent: string;
144→    severity?: "info" | "warning" | "conflict";
145→  },
146→): Promise<{ observationId: string; observationRecord: RecordId<"observation"> }> {
147→  return createObservationDirectly(surreal, workspaceId, {
148→    text: opts.text,
149→    sourceAgent: opts.sourceAgent,
150→    severity: opts.severity ?? "info",
151→  });
152→}
153→
154→/**
155→ * Creates a learning to use as evidence.
156→ * Returns the record ID for use in evidence_refs.
157→ */
158→export async function createEvidenceLearning(
159→  surreal: Surreal,
160→  workspaceId: string,
161→  opts: {
162→    text: string;
163→    learningType?: "constraint" | "instruction" | "precedent";
164→  },
165→): Promise<{ learningId: string; learningRecord: RecordId<"learning"> }> {
166→  return createLearningDirectly(surreal, workspaceId, {
167→    text: opts.text,
168→    learningType: opts.learningType ?? "instruction",
169→  });
170→}
171→
172→/**
173→ * Creates a git_commit to use as evidence.
174→ * Returns the record ID for use in evidence_refs.
175→ */
176→export async function createEvidenceGitCommit(
177→  surreal: Surreal,
178→  workspaceId: string,
179→  opts: {
180→    message: string;
181→    sha?: string;
182→    repository?: string;
183→  },
184→): Promise<{ commitId: string; commitRecord: RecordId<"git_commit"> }> {
185→  return createGitCommitDirectly(surreal, workspaceId, opts.sha ?? crypto.randomUUID().replace(/-/g, "").slice(0, 40), {
186→    message: opts.message,
187→    repository: opts.repository,
188→  });
189→}
190→
191→// ---------------------------------------------------------------------------
192→// Intent with Evidence Helpers
193→// ---------------------------------------------------------------------------
194→
195→/**
196→ * Creates a draft intent with evidence references.
197→ * The evidence_refs are stored as an array of RecordId on the intent.
198→ */
199→export async function createIntentWithEvidence(
200→  surreal: Surreal,
201→  workspaceId: string,
202→  requesterId: string,
203→  opts: {
204→    goal: string;
205→    reasoning: string;
206→    priority?: number;
207→    evidenceRefs: RecordId[];
208→    actionSpec?: { provider: string; action: string; params: Record<string, unknown> };
209→  },
210→): Promise<{ intentId: string; intentRecord: RecordId<"intent"> }> {
211→  const result = await createIntentDirectly(surreal, workspaceId, requesterId, {
212→    goal: opts.goal,
213→    reasoning: opts.reasoning,
214→    priority: opts.priority,
215→    actionSpec: opts.actionSpec ?? { provider: "test", action: "test", params: {} },
216→  });
217→
218→  // Add evidence_refs to the intent record
219→  await surreal.query(
220→    `UPDATE $intent SET evidence_refs = $refs;`,
221→    {
222→      intent: result.intentRecord,
223→      refs: opts.evidenceRefs,
224→    },
225→  );
226→
227→  return { intentId: result.intentId, intentRecord: result.intentRecord };
228→}
229→
230→/**
231→ * Creates a draft intent without evidence references.
232→ * Used for scenarios testing missing evidence behavior.
233→ */
234→export async function createIntentWithoutEvidence(
235→  surreal: Surreal,
236→  workspaceId: string,
237→  requesterId: string,
238→  opts: {
239→    goal: string;
240→    reasoning: string;
241→    priority?: number;
242→    actionSpec?: { provider: string; action: string; params: Record<string, unknown> };
243→  },
244→): Promise<{ intentId: string; intentRecord: RecordId<"intent"> }> {
245→  const result = await createIntentDirectly(surreal, workspaceId, requesterId, {
246→    goal: opts.goal,
247→    reasoning: opts.reasoning,
248→    priority: opts.priority,
249→    actionSpec: opts.actionSpec ?? { provider: "test", action: "test", params: {} },
250→  });
251→
252→  return { intentId: result.intentId, intentRecord: result.intentRecord };
253→}
254→
255→// ---------------------------------------------------------------------------
256→// Workspace Enforcement Configuration
257→// ---------------------------------------------------------------------------
258→
259→/**
260→ * Sets the evidence enforcement mode on a workspace.
261→ * Modes: "bootstrap" (no requirements), "soft" (penalty), "hard" (reject).
262→ */
263→export async function setWorkspaceEnforcementMode(
264→  surreal: Surreal,
265→  workspaceId: string,
266→  mode: EvidenceEnforcementMode,
267→): Promise<void> {
268→  const workspaceRecord = new RecordId("workspace", workspaceId);
269→  await surreal.query(
270→    `UPDATE $ws SET evidence_enforcement = $mode;`,
271→    { ws: workspaceRecord, mode },
272→  );
273→}
274→
275→/**
276→ * Sets the evidence enforcement maturity threshold on a workspace.
277→ * When the workspace reaches this threshold, enforcement auto-transitions.
278→ */
279→export async function setEnforcementThreshold(
280→  surreal: Surreal,
281→  workspaceId: string,
282→  threshold: EvidenceEnforcementThreshold,
283→): Promise<void> {
284→  const workspaceRecord = new RecordId("workspace", workspaceId);
285→  await surreal.query(
286→    `UPDATE $ws SET evidence_enforcement_threshold = $threshold;`,
287→    { ws: workspaceRecord, threshold },
288→  );
289→}
290→
291→/**
292→ * Sets the minimum evidence age (in minutes) on a workspace.
293→ */
294→export async function setMinimumEvidenceAge(
295→  surreal: Surreal,
296→  workspaceId: string,
297→  minutes: number,
298→): Promise<void> {
299→  const workspaceRecord = new RecordId("workspace", workspaceId);
300→  await surreal.query(
301→    `UPDATE $ws SET min_evidence_age_minutes = $minutes;`,
302→    { ws: workspaceRecord, minutes },
303→  );
304→}
305→
306→// ---------------------------------------------------------------------------
307→// Evidence Verification Queries
308→// ---------------------------------------------------------------------------
309→
310→/**
311→ * Reads the evidence verification result from an intent record.
312→ */
313→export async function getEvidenceVerification(
314→  surreal: Surreal,
315→  intentId: string,
316→): Promise<EvidenceVerification | undefined> {
317→  const intentRecord = new RecordId("intent", intentId);
318→  const rows = (await surreal.query(
319→    `SELECT evidence_verification FROM $intent;`,
320→    { intent: intentRecord },
321→  )) as Array<Array<{ evidence_verification?: EvidenceVerification }>>;
322→  return rows[0]?.[0]?.evidence_verification;
323→}
324→
325→/**
326→ * Reads the evidence_refs from an intent record.
327→ */
328→export async function getEvidenceRefs(
329→  surreal: Surreal,
330→  intentId: string,
331→): Promise<RecordId[] | undefined> {
332→  const intentRecord = new RecordId("intent", intentId);
333→  const rows = (await surreal.query(
334→    `SELECT evidence_refs FROM $intent;`,
335→    { intent: intentRecord },
336→  )) as Array<Array<{ evidence_refs?: RecordId[] }>>;
337→  return rows[0]?.[0]?.evidence_refs;
338→}
339→
340→/**
341→ * Reads the workspace enforcement mode.
342→ */
343→export async function getWorkspaceEnforcementMode(
344→  surreal: Surreal,
345→  workspaceId: string,
346→): Promise<EvidenceEnforcementMode | undefined> {
347→  const workspaceRecord = new RecordId("workspace", workspaceId);
348→  const rows = (await surreal.query(
349→    `SELECT evidence_enforcement FROM $ws;`,
350→    { ws: workspaceRecord },
351→  )) as Array<Array<{ evidence_enforcement?: EvidenceEnforcementMode }>>;
352→  return rows[0]?.[0]?.evidence_enforcement;
353→}
354→
355→/**
356→ * Counts confirmed decisions in a workspace.
357→ */
358→export async function countConfirmedDecisions(
359→  surreal: Surreal,
360→  workspaceId: string,
361→): Promise<number> {
362→  const workspaceRecord = new RecordId("workspace", workspaceId);
363→  const rows = (await surreal.query(
364→    `SELECT count() AS total FROM decision WHERE workspace = $ws AND status = "confirmed" GROUP ALL;`,
365→    { ws: workspaceRecord },
366→  )) as Array<Array<{ total: number }>>;
367→  return rows[0]?.[0]?.total ?? 0;
368→}
369→
370→/**
371→ * Counts completed tasks in a workspace.
372→ */
373→export async function countCompletedTasks(
374→  surreal: Surreal,
375→  workspaceId: string,
376→): Promise<number> {
377→  const workspaceRecord = new RecordId("workspace", workspaceId);
