  surreal: Surreal,
  intentId: string,
): Promise<IntentRecord | undefined> {
  const record = new RecordId("intent", intentId);
  const [rows] = await surreal.query<[IntentRecord[]]>(
    "SELECT * FROM $record;",
    { record },
  );
  return rows[0];
}

