  1→/**
  2→ * Milestone 2: Semantic Verification Pipeline
  3→ *
  4→ * Traces: Roadmap Phase 02 (02-01, 02-02, 02-03, 02-04)
  5→ *   - US-1 (AC-1.1 through AC-1.6): LLM semantic contradiction detection
  6→ *   - R1: LLM verification pipeline integration
  7→ *   - R2: Skip optimization
  8→ *   - R3: LLM fallback on failure
  9→ *   - R5: Structured output
 10→ *
 11→ * IMPORTANT: These tests call a real LLM. OBSERVER_MODEL must be set in .env.
 12→ *
 13→ * Validates that:
 14→ * - LLM detects semantic contradictions between decisions and completed tasks
 15→ * - LLM confirms matches when task aligns with decision
 16→ * - Low confidence verdicts downgrade to inconclusive
 17→ * - LLM failure falls back to deterministic verdict
 18→ * - Skip optimization bypasses LLM when appropriate
 19→ * - Multiple observes edges link contradiction to both task and decision
 20→ * - Evidence refs are post-validated against workspace entities
 21→ *
 22→ * Driving ports:
 23→ *   POST /api/observe/task/:id         (SurrealQL EVENT target)
 24→ *   SurrealDB direct queries           (verification of outcomes)
 25→ */
 26→import { describe, expect, it, beforeAll } from "bun:test";
 27→import {
 28→  setupObserverSuite,
 29→  wireObserverEvents,
 30→  setupObserverWorkspace,
 31→  triggerTaskCompletion,
 32→  waitForObservation,
 33→  getObservationsForEntity,
 34→  createProject,
 35→  createTaskInProject,
 36→  createDecisionInProject,
 37→  setWorkspaceObserverSkip,
 38→  countObservations,
 39→} from "./llm-reasoning-test-kit";
 40→
 41→const getRuntime = setupObserverSuite("observer_llm_m2_verification");
 42→
 43→beforeAll(async () => {
 44→  const { surreal, port } = getRuntime();
 45→  await wireObserverEvents(surreal, port);
 46→});
 47→
 48→// =============================================================================
 49→// AC-1.1: LLM detects semantic contradiction on task completion
 50→// =============================================================================
 51→
 52→describe("Milestone 2: Semantic Contradiction Detection (AC-1.1)", () => {
 53→  it("LLM detects mismatch when task contradicts confirmed decision", async () => {
 54→    const { baseUrl, surreal } = getRuntime();
 55→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "llm-contra-1");
 56→    const { projectId } = await createProject(surreal, workspaceId, "Contradiction Project");
 57→
 58→    // Given a confirmed decision about API standardization
 59→    await createDecisionInProject(surreal, workspaceId, projectId, {
 60→      summary: "Standardize on tRPC for all new API endpoints. REST endpoints are forbidden for new services.",
 61→      rationale: "Type safety and consistency across the codebase",
 62→    });
 63→
 64→    // And a task that implements REST endpoints (contradicts the decision)
 65→    const { taskId } = await createTaskInProject(surreal, workspaceId, projectId, {
 66→      title: "Implement billing API with REST endpoints",
 67→      description: "Build a RESTful billing API with Express routes for payment processing, invoice generation, and subscription management.",
 68→      status: "in_progress",
 69→    });
 70→
 71→    // When the task is marked as completed
 72→    await triggerTaskCompletion(surreal, taskId);
 73→
 74→    // Then the observer creates a contradiction observation
 75→    const observations = await waitForObservation(surreal, "task", taskId, 60_000);
 76→    expect(observations.length).toBeGreaterThanOrEqual(1);
 77→
 78→    const obs = observations[0];
 79→    expect(obs.source_agent).toBe("observer_agent");
 80→    // And the observation indicates a conflict
 81→    expect(obs.severity).toBe("conflict");
 82→    expect(obs.observation_type).toBe("contradiction");
 83→    // And the source indicates LLM reasoning was used
 84→    expect(obs.source).toBe("llm");
 85→    // And the observation text describes the specific conflict
 86→    expect(obs.text).toBeTruthy();
 87→    expect(obs.text.length).toBeGreaterThan(30);
 88→  }, 120_000);
 89→
 90→  it("LLM creates observes edges to both task and contradicted decision", async () => {
 91→    const { baseUrl, surreal } = getRuntime();
 92→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "llm-edges-1");
 93→    const { projectId } = await createProject(surreal, workspaceId, "Edge Test Project");
 94→
 95→    // Given a confirmed decision and a contradicting task
 96→    const { decisionId } = await createDecisionInProject(surreal, workspaceId, projectId, {
 97→      summary: "All database queries must use parameterized statements. No string concatenation in SQL.",
 98→      rationale: "SQL injection prevention",
 99→    });
100→
101→    const { taskId } = await createTaskInProject(surreal, workspaceId, projectId, {
102→      title: "Build admin search with dynamic SQL string construction",
103→      description: "Implement admin search by building SQL queries via string concatenation based on filter parameters.",
104→      status: "in_progress",
105→    });
106→
107→    // When the task is marked as completed
108→    await triggerTaskCompletion(surreal, taskId);
109→
110→    // Then the observer creates an observation
111→    const observations = await waitForObservation(surreal, "task", taskId, 60_000);
112→    expect(observations.length).toBeGreaterThanOrEqual(1);
113→
114→    // And the observation has observes edges to the task
115→    // (edge to task is verified by waitForObservation finding it via reverse traversal)
116→    // The edge to decision is verified separately:
117→    const decisionObs = await getObservationsForEntity(surreal, "decision", decisionId);
118→    // At least one observation should link to the decision
119→    expect(decisionObs.length).toBeGreaterThanOrEqual(1);
120→  }, 120_000);
121→});
122→
123→// =============================================================================
124→// AC-1.2: No contradiction creates match observation
125→// =============================================================================
126→
127→describe("Milestone 2: Match Confirmation (AC-1.2)", () => {
128→  it("LLM confirms match when task aligns with decision", async () => {
129→    const { baseUrl, surreal } = getRuntime();
130→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "llm-match-1");
131→    const { projectId } = await createProject(surreal, workspaceId, "Match Project");
132→
133→    // Given a confirmed decision about TypeScript usage
134→    await createDecisionInProject(surreal, workspaceId, projectId, {
135→      summary: "Use TypeScript for all backend services. No plain JavaScript files.",
136→      rationale: "Type safety and maintainability",
137→    });
138→
139→    // And a task that aligns with the decision
140→    const { taskId } = await createTaskInProject(surreal, workspaceId, projectId, {
141→      title: "Implement authentication middleware in TypeScript",
