  1→/**
  2→ * Skill Route Handlers
  3→ *
  4→ * Factory function returning route handlers for the skill catalog API.
  5→ * Follows the handler factory pattern used by policy-route.ts.
  6→ *
  7→ * Driving ports:
  8→ *   POST /api/workspaces/:wsId/skills              (create)
  9→ *   GET  /api/workspaces/:wsId/skills              (list with ?status filter)
 10→ *   POST /api/workspaces/:wsId/skills/:id/activate (activate draft -> active)
 11→ *   POST /api/workspaces/:wsId/skills/:id/deprecate (deprecate active -> deprecated)
 12→ */
 13→import { RecordId } from "surrealdb";
 14→import { trace } from "@opentelemetry/api";
 15→import { HttpError } from "../http/errors";
 16→import { jsonError, jsonResponse } from "../http/response";
 17→import type { ServerDependencies } from "../runtime/types";
 18→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 19→import { createSkill, listSkills, getSkillDetail, updateSkill, deleteSkill, activateSkill, deprecateSkill } from "./skill-queries";
 20→import type { SkillSource, SkillStatus } from "./types";
 21→import { log } from "../telemetry/logger";
 22→
 23→// ---------------------------------------------------------------------------
 24→// Identity resolution (session -> person -> identity)
 25→// ---------------------------------------------------------------------------
 26→
 27→type IdentityInfo = {
 28→  identityRecord: RecordId<"identity", string>;
 29→};
 30→
 31→async function resolveIdentityFromSession(
 32→  deps: ServerDependencies,
 33→  request: Request,
 34→): Promise<IdentityInfo | Response> {
 35→  const session = await deps.auth.api.getSession({ headers: request.headers });
 36→  if (!session?.user?.id) {
 37→    return jsonError("authentication required", 401);
 38→  }
 39→
 40→  const personRecord = new RecordId("person", session.user.id);
 41→
 42→  const [identityRows] = await deps.surreal.query<[RecordId<"identity", string>[]]>(
 43→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
 44→    { person: personRecord },
 45→  );
 46→  const identityRecord = identityRows[0] as RecordId<"identity", string> | undefined;
 47→  if (!identityRecord) {
 48→    return jsonError("identity not found for user", 500);
 49→  }
 50→
 51→  return { identityRecord };
 52→}
 53→
 54→// ---------------------------------------------------------------------------
 55→// Shared helpers
 56→// ---------------------------------------------------------------------------
 57→
 58→function isResponse(value: unknown): value is Response {
 59→  return value instanceof Response;
 60→}
 61→
 62→async function resolveWorkspace(
 63→  deps: ServerDependencies,
 64→  workspaceId: string,
 65→  logEvent: string,
 66→): Promise<RecordId<"workspace", string> | Response> {
 67→  try {
 68→    return await resolveWorkspaceRecord(deps.surreal, workspaceId);
 69→  } catch (error) {
 70→    if (error instanceof HttpError) {
 71→      return jsonError(error.message, error.status);
 72→    }
 73→    log.error(logEvent, "Failed to resolve workspace", error, { workspaceId });
 74→    return jsonError("failed to resolve workspace", 500);
 75→  }
 76→}
 77→
 78→const VALID_SKILL_STATUSES: ReadonlySet<string> = new Set(["draft", "active", "deprecated"]);
 79→
 80→// ---------------------------------------------------------------------------
 81→// Validation
 82→// ---------------------------------------------------------------------------
 83→
 84→type CreateSkillBody = {
 85→  name: string;
 86→  description: string;
 87→  version: string;
 88→  source: SkillSource;
 89→  required_tool_ids?: string[];
 90→};
 91→
 92→function validateCreateSkillBody(body: unknown): { valid: true; parsed: CreateSkillBody } | { valid: false; error: string } {
 93→  if (!body || typeof body !== "object") {
 94→    return { valid: false, error: "request body is required" };
 95→  }
 96→
 97→  const raw = body as Record<string, unknown>;
 98→
 99→  if (!raw.name || typeof raw.name !== "string") {
100→    return { valid: false, error: "name is required" };
101→  }
102→  if (!raw.description || typeof raw.description !== "string") {
103→    return { valid: false, error: "description is required" };
104→  }
105→  if (!raw.version || typeof raw.version !== "string") {
106→    return { valid: false, error: "version is required" };
107→  }
108→  if (!raw.source || typeof raw.source !== "object") {
109→    return { valid: false, error: "source is required" };
110→  }
111→
112→  return {
113→    valid: true,
114→    parsed: {
115→      name: raw.name as string,
116→      description: raw.description as string,
117→      version: raw.version as string,
118→      source: raw.source as SkillSource,
119→      required_tool_ids: Array.isArray(raw.required_tool_ids) ? raw.required_tool_ids as string[] : undefined,
120→    },
121→  };
122→}
123→
124→// ---------------------------------------------------------------------------
125→// Route handler factory
126→// ---------------------------------------------------------------------------
127→
128→export function createSkillRouteHandlers(deps: ServerDependencies) {
129→  return {
130→    handleCreate: (workspaceId: string, request: Request) =>
131→      handleCreateSkill(deps, workspaceId, request),
132→    handleList: (workspaceId: string, request: Request) =>
133→      handleListSkills(deps, workspaceId, request),
134→    handleGetDetail: (workspaceId: string, skillId: string, request: Request) =>
135→      handleGetDetailSkill(deps, workspaceId, skillId, request),
136→    handleUpdate: (workspaceId: string, skillId: string, request: Request) =>
137→      handleUpdateSkill(deps, workspaceId, skillId, request),
138→    handleDelete: (workspaceId: string, skillId: string, request: Request) =>
139→      handleDeleteSkill(deps, workspaceId, skillId, request),
140→    handleActivate: (workspaceId: string, skillId: string, request: Request) =>
141→      handleActivateSkill(deps, workspaceId, skillId, request),
142→    handleDeprecate: (workspaceId: string, skillId: string, request: Request) =>
143→      handleDeprecateSkill(deps, workspaceId, skillId, request),
144→  };
145→}
146→
147→// ---------------------------------------------------------------------------
148→// POST /api/workspaces/:workspaceId/skills
149→// ---------------------------------------------------------------------------
150→
151→async function handleCreateSkill(
152→  deps: ServerDependencies,
153→  workspaceId: string,
154→  request: Request,
155→): Promise<Response> {
156→  const identityOrError = await resolveIdentityFromSession(deps, request);
157→  if (isResponse(identityOrError)) return identityOrError;
